CREATE TABLE
  `assessments` (
    `id` bigint UNSIGNED NOT NULL,
    `user_id` bigint UNSIGNED NOT NULL,
    `first_name` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `last_name` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `email` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `mobile` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `city` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `weight` decimal(5, 2) NOT NULL,
      `height` decimal(5, 2) NOT NULL,
      `bmi` decimal(5, 2) DEFAULT NULL,
      `fat_percentage` decimal(5, 2) NOT NULL,
      `muscle_mass` decimal(5, 2) DEFAULT NULL,
      `water_percentage` decimal(5, 2) DEFAULT NULL,
      `consultation_type` enum ('in_person', 'phone') CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `status` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
      `gender` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `age` int DEFAULT NULL,
      `goal` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `birth_date` date DEFAULT NULL,
      `activity_level` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `calories_needed` decimal(8, 2) DEFAULT NULL,
      `protein` decimal(8, 2) DEFAULT NULL,
      `carbohydrates` decimal(8, 2) DEFAULT NULL,
      `calories_intake` decimal(8, 2) DEFAULT NULL,
      `created_at` timestamp NULL DEFAULT NULL,
      `updated_at` timestamp NULL DEFAULT NULL
  ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

