--
-- Table structure for table `meal_translations`
--
CREATE TABLE
  `meal_translations` (
    `id` bigint UNSIGNED NOT NULL,
    `meal_variant_id` bigint UNSIGNED NOT NULL,
    `locale` enum ('en', 'ar') CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
      `title` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
      `description` text CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci,
      `created_at` timestamp NULL DEFAULT NULL,
      `updated_at` timestamp NULL DEFAULT NULL
  ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

