-- --------------------------------------------------------
--
-- Table structure for table `XXmeal_variants`
--
CREATE TABLE
  `XXmeal_variants` (
    `id` bigint UNSIGNED NOT NULL,
    `meal_id` varchar(191) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `calorie_level` smallint UNSIGNED NOT NULL,
      `week` tinyint UNSIGNED NOT NULL,
      `day` enum (
        'saturday',
        'sunday',
        'monday',
        'tuesday',
        'wednesday',
        'thursday'
      ) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
      `meal_type` enum (
        'breakfast',
        'lunch',
        'dinner',
        'snack1',
        'snack2'
      ) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
      `option_no` tinyint UNSIGNED NOT NULL,
      `price` decimal(8, 2) NOT NULL DEFAULT '0.00',
      `image` varchar(255) CHARACTER
    SET
      utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
      `created_at` timestamp NULL DEFAULT NULL,
      `updated_at` timestamp NULL DEFAULT NULL
  ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

